2	import { AlertCircle, Zap, X } from "lucide-react";
3	import { useState } from "react";
4	import { useNavigate } from "react-router-dom";
5	import { motion, AnimatePresence } from "framer-motion";
6	
7	interface UsageLimitBannerProps {
8	  current: number;
9	  limit: number;
10	  feature: string;
11	}
12	
13	const UsageLimitBanner = ({ current, limit, feature }: UsageLimitBannerProps) => {
14	  const navigate = useNavigate();
15	  const [dismissed, setDismissed] = useState(false);
16	  const percentage = (current / limit) * 100;
17	  const isAtLimit = current >= limit;
18	  const isNearLimit = percentage >= 80 && !isAtLimit;
19	
20	  if ((!isAtLimit && !isNearLimit) || dismissed) return null;
21	
22	  return (
23	    <AnimatePresence>
24	      <motion.div
25	        initial={{ opacity: 0, y: -8 }}
26	        animate={{ opacity: 1, y: 0 }}
27	        exit={{ opacity: 0, y: -8 }}
28	        className={`flex items-center gap-3 px-4 py-2.5 text-sm ${
29	          isAtLimit
30	            ? "bg-destructive/10 border-b border-destructive/20 text-destructive"
31	            : "bg-amber-500/10 border-b border-amber-500/20 text-amber-700 dark:text-amber-400"
32	        }`}
33	      >
34	        <AlertCircle className="w-4 h-4 flex-shrink-0" />
35	        <span className="flex-1">
36	          {isAtLimit
37	            ? `You've reached your ${feature} limit (${current}/${limit}). Upgrade to continue.`
38	            : `You're almost at your ${feature} limit — ${current}/${limit} used.`}
39	        </span>
40	        <Button
41	          size="sm"
42	          className="h-7 text-xs bg-bronze hover:bg-bronze/90 text-background gap-1 flex-shrink-0"
43	          onClick={() => navigate("/profile/payments-billing")}
44	        >
45	          <Zap className="w-3 h-3" />
46	          Upgrade
47	        </Button>
48	        <button
49	          onClick={() => setDismissed(true)}
50	          className="p-1 rounded hover:bg-black/10 transition-colors flex-shrink-0"
51	        >
52	          <X className="w-3.5 h-3.5" />
53	        </button>
54	      </motion.div>
55	    </AnimatePresence>
56	  );
57	};
58	
59	export default UsageLimitBanner;
