22	function sanitizePrompt(prompt: string): string {
23	  return prompt
24	    .trim()
25	    .slice(0, 2000)
26	    .replace(/<[^>]*>/g, '')
27	    .replace(/[^\x20-\x7E\n\r\t\u00C0-\u024F\u0400-\u04FF]/g, '');
28	}
